#include <stdio.h>
#include <stdlib.h>

int count_inversions(int *arr, int n) {
    int inv = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (arr[i] > arr[j]) ++inv;
        }
    }
    return inv;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, Q; scanf("%d %d", &N, &Q);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        int *B = (int*)malloc((N + Q) * sizeof(int)); // enough space
        int sizeA = N, sizeB = 0;
        for (int move = 0; move < Q; ++move) {
            int L, R, K; scanf("%d %d %d", &L, &R, &K);
            L--; R--; K--;
            int segLen = R - L + 1;
            // shift B to make room at position K
            for (int i = sizeB - 1; i >= K; --i) B[i + segLen] = B[i];
            // copy segment from A to B
            for (int i = 0; i < segLen; ++i) B[K + i] = A[L + i];
            sizeB += segLen;
            // remove segment from A by shifting left
            for (int i = R + 1; i < sizeA; ++i) A[i - segLen] = A[i];
            sizeA -= segLen;
            int inv = count_inversions(B, sizeB);
            printf("%d\n", inv);
        }
        free(A);
        free(B);
    }
    return 0;
}

