#include <bits/stdc++.h>
using namespace std;

long long countInv(const vector<int>& v) {
    long long inv = 0;
    for (size_t i = 0; i < v.size(); ++i)
        for (size_t j = i + 1; j < v.size(); ++j)
            if (v[i] > v[j]) ++inv;
    return inv;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int N, Q; cin >> N >> Q;
        vector<int> A(N);
        for (int &x : A) cin >> x;
        vector<int> B; B.reserve(N + Q);
        for (int i = 0; i < Q; ++i) {
            int L, R, K; cin >> L >> R >> K;
            --L; --R; --K;
            vector<int> segment(A.begin() + L, A.begin() + R + 1);
            B.insert(B.begin() + K, segment.begin(), segment.end());
            A.erase(A.begin() + L, A.begin() + R + 1);
            cout << countInv(B) << '\n';
        }
    }
    return 0;
}

