import java.io.*;
import java.util.*;

public class Main {
    private static long countInv(List<Integer> list) {
        long inv = 0;
        for (int i = 0; i < list.size(); i++) {
            for (int j = i + 1; j < list.size(); j++) {
                if (list.get(i) > list.get(j)) inv++;
            }
        }
        return inv;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int Q = Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            List<Integer> A = new ArrayList<>();
            for (int i = 0; i < N; i++) A.add(Integer.parseInt(st.nextToken()));
            List<Integer> B = new ArrayList<>();
            for (int q = 0; q < Q; q++) {
                st = new StringTokenizer(br.readLine());
                int L = Integer.parseInt(st.nextToken()) - 1;
                int R = Integer.parseInt(st.nextToken()) - 1;
                int K = Integer.parseInt(st.nextToken()) - 1;
                List<Integer> segment = new ArrayList<>(A.subList(L, R + 1));
                B.addAll(K, segment);
                for (int i = 0; i < segment.size(); i++) A.remove(L);
                System.out.println(countInv(B));
            }
        }
    }
}

